.sticky-sidebar {
  position: sticky;
  top: 100px; /* adjust for your header height */
  align-self: start;
}

/* Make FacetWP map responsive */
.sticky-sidebar #facetwp-map {
  width: 100% !important;
  height: 100% !important;
  min-height: 400px; /* base height for desktop */
}

/* Ensure parent containers don’t constrain it */
.sticky-sidebar #facetwp-map iframe,
.sticky-sidebar #facetwp-map > div {
  width: 100% !important;
  height: 100% !important;
}

/* Optional: control aspect ratio for better responsiveness */
.sticky-sidebar #facetwp-map {
  aspect-ratio: 16 / 9;
  height: auto;
  min-height: 350px;
}

/* Adjust for smaller screens */
@media (max-width: 768px) {
  .sticky-sidebar #facetwp-map {
    aspect-ratio: 4 / 3;
    min-height: 300px;
  }
}

.grecaptcha-badge { 
    visibility: hidden; 
}

.home-hero-with-map {
  position: relative;
  overflow: hidden;
  height: 540px;
}

.home-hero-map-bg {
  position: absolute;
  inset: 0;
  z-index: 0;
  overflow: hidden;
}

/* Ensure picture/figure don't contribute layout */
.home-hero-map-bg picture,
.home-hero-map-bg figure {
  position: absolute;
  inset: 0;
  margin: 0;
  width: 100%;
  height: 100%;
}

.home-hero-map-bg img {
  position: absolute;
  inset: 0;
  width: 100% !important;
  height: 100% !important;
  max-width: none !important;
  max-height: none !important;
  object-fit: cover;
  object-position: 50% 50%;
  display: block;
}

.home-hero-map-bg::after {
  content: "";
  position: absolute;
  inset: 0;
  background: rgba(0,0,0,0.7);
  z-index: 1;
}

.home-hero-content {
  position: relative;
  z-index: 2;
}

/** Renderer **/
/* Wrapper for hero */
.render-hero-with-map {
    position: relative;
    overflow: visible;
}

/* Map container positioned behind content */
.render-hero-map-bg {
    position: absolute;
    inset: 0;              /* top:0; right:0; bottom:0; left:0 */
    z-index: 0;
}

.render-hero-map-bg .facetwp-facet {
    position: absolute;
    inset: 0;
	  z-index: 1;
	  margin-bottom: 0px;
}

.render-hero-map-bg::after {
    content: "";
    position: absolute;
    inset: 0;
    z-index: 2; /* above map, below content */
}

/* Make sure the FacetWP map fills the container */
.render-hero-with-map #facetwp-map {
    width: 100% !important;
    height: 100% !important;
}

/* Your hero content on top of the map */
.render-hero-content {
    position: relative;
    z-index: 1;
}

/* Make the map completely read-only / not clickable */
.render-hero-map-bg::after {
    pointer-events: none;
}

.render-hero-map-bg {
    pointer-events: auto; /* allow map to init properly */
}

.render-hero-with-map .facetwp-map-filtering {
  display: none;
}

.render-hero-with-map .facetwp-template {
  display: none;
}
/** /Renderer **/

/* Outer wrapper so overlay can position itself */
.locked-card {
    position: relative;
    overflow: hidden;
}

/* The real content: blur it */
.locked-card-content {
    filter: blur(6px);
    pointer-events: none; /* prevent clicks on blurred content */
}

/* Overlay container with CTA */
.locked-card-overlay {
    position: absolute;
    inset: 0; /* top:0; right:0; bottom:0; left:0 */
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    text-align: center;
    padding: 1.5rem;
    z-index: 3;
}

/* Semi-transparent veil behind the CTA text/button */
.locked-card-overlay::before {
    content: "";
    position: absolute;
    inset: 0;
    background: rgba(255, 255, 255, 0.6); /* adjust opacity/color as you like */
    backdrop-filter: blur(4px); /* optional extra blur if supported */
    z-index: -1;
}

/* Make sure text and buttons in the overlay sit above the veil */
.locked-card-overlay > * {
    position: relative;
    z-index: 1;
}
/* Booking.com-style floating search bar */
.home-search-bar {
    max-width: 900px;
    width: calc(100% - 32px);
    padding: 20px;
    border-radius: 12px;
    background: #fff;
    box-shadow: 0 4px 20px rgba(0,0,0,0.12);

    display: flex;
    gap: 16px;
    align-items: center;
}
.search-grid {
	width: 100%;
}

.home-second-section {
    position: relative;
	  padding-top: 40px; /* matches the absolute overlap */
}

.home-second-section .home-search-bar {
    max-width: 900px;
    width: calc(100% - 32px);
    margin: -80px auto 0px;  /* pull up 40px over the seam */
    padding: 20px;
    border-radius: 12px;
    background: #fff;
    box-shadow: 0 4px 20px rgba(0,0,0,0.12);

    display: flex;
    gap: 16px;
    align-items: center;
}

/* Responsive stack on mobile */
@media (max-width: 768px) {
    .home-search-bar {
        flex-direction: column;
        gap: 12px;
        bottom: -30px;
    }
}

/* Wrap the proximity facet nicely inside your bar */
.home-search-bar .facetwp-facet-gps {
    flex: 1;
}

.home-search-bar .facetwp-facet {
		  margin-bottom: 0px;
}

/* Input styling */
.home-search-bar .facetwp-facet-gps input[type="text"] {
    padding: 10px 12px;
    border-radius: 8px;
    border: 1px solid #ddd;
    font-size: 14px;
	  min-width: 100%;
}

/* Optional: hide radius selector for now */
.home-search-bar .facetwp-facet-gps .facetwp-radius {
    display: none;
}
.home-search-bar .facetwp-facet-gps .facetwp-radius-unit {
    display: none;
}
.home-search-bar .facetwp-facet-gps .facetwp-radius-dist {
    display: none;
}

.home-search-bar .facetwp-facet-date {
    display: flex;
    gap: 8px;
    align-items: center;
}

.home-search-bar .facetwp-facet-date input[type="text"] {
    flex: 1 1 0;
    min-width: 0;
	  max-width: 40%;
    padding: 10px 12px;
    border-radius: 8px;
    border: 1px solid #ddd;
    font-size: 14px;
}

@media (max-width: 768px) {
    .home-search-bar .facetwp-facet-date {
        flex-direction: column;
        gap: 6px;
    }
}

.p4n-card {
  position: relative;
  overflow: hidden; /* prevents zoomed image from spilling out */
}

.p4n-card-image {
  width: 100%;
  height: 100%; /* match editor setting */
  object-fit: cover;
  transition: transform 0.4s cubic-bezier(.47,.01,.37,.98);
}

/* The round icon container (no inner img now) */
.p4n-card-access {
  position: absolute;
  left: 1.5rem;      /* align with body padding */
  top: auto;        /* adjust for your image height */
  transform: translateY(-50%);
  width: 48px;
  height: 48px;
  border-radius: 50%;
  border: 4px solid #fff;
  overflow: hidden;
  z-index: 2;
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;

	transition: transform .4s cubic-bezier(.47,.01,.37,.98);
}

.type-le_camp .p4n-card-access {
  background-image: url('/app/uploads/camp2.png');
}

.type-le_event .p4n-card-access {
  background-image: url('/app/uploads/event3.png');
}

.type-le_location .p4n-card-access {
  background-image: url('/app/uploads/location2.png');
}

.type-le_course .p4n-card-access {
  background-image: url('/app/uploads/course2.png');
}

/* Title: clamp to 2 lines */
.p4n-card-title {
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  line-height: 1.2;
  min-height: calc(1.2em * 2);
  max-height: calc(1.2em * 2);  margin: 0 0 0.5rem;
}

.p4n-card-title a {
  color: #165dd7;
  transition: color .4s cubic-bezier(.47,.01,.37,.98);
  text-decoration: none;
}

/* Excerpt: clamp to 5 lines */
.p4n-card-excerpt {
  display: -webkit-box;
  -webkit-line-clamp: 5;
  -webkit-box-orient: vertical;
  overflow: hidden;
  min-height: 120px;
  margin: 0 0 0.5rem;
}

/* Footer container: right aligned row */
.p4n-card-footer {
  display: flex;
  justify-content: flex-end;   /* push content to the right */
  padding: 0 0.5rem 0.1rem;
  color: #8a8fab;
  font-size: 0.9rem;
  overflow: hidden;            /* hide overflow in the footer */
}

/* The p inside becomes a flex row with icon + text */
.p4n-card-footer .gb-headline {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  min-width: 0;                /* allow p to shrink inside the flex footer */
  margin: 0;                   /* remove default paragraph margin */
}

/* Icon: fixed size, doesn't shrink */
.p4n-card-footer .gb-icon {
  flex: 0 0 auto;
}

/* Text: this is what actually ellipsizes */
.p4n-card-footer .gb-headline-text {
  display: inline-block;
  min-width: 0;                /* allow text to shrink */
  max-width: 100%;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;     /* show beginning, cut off the end with … */
}

/* 1) Zoom image slightly on card hover */
.p4n-card.cond-show:hover .p4n-card-image {
  transform: scale(1.1) rotate(.5deg);
}

/* 2) Lift the access icon on card hover */
.p4n-card.cond-show:hover .p4n-card-access {
  transform: translateY(-0.5rem);
}

/* 3) Change title color on card hover */
.p4n-card.cond-show:hover .p4n-card-title a {
  color: #27d9a1;
}

/* Heart "add to favorites" overlay */
.p4n-card-fav {
  position: absolute;
  top: 0.75rem;
  right: 0.75rem;
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 3;
  cursor: pointer;
}

/* The heart itself (icon, text or SVG) */
.p4n-card-fav svg {
  color: #ed4c5c; /* heart red */
  fill: #ed4c5c;
  text-decoration: none;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

/* the magic */
.p4n-card-fav .heart-full { display: none; }
.p4n-card-fav[data-liked="1"] .heart-full { display: inline; }
.p4n-card-fav[data-liked="1"] .heart-empty { display: none; }

/* Desktop: hide the user menu completely */
@media (min-width: 769px) {
    .gp-mobile-user-menu {
        display: none;
    }
}

/* Mobile only overrides */
@media (max-width: 768px) {

    /* Make sure our custom UL is NOT hidden by the theme rule */
    #mobile-menu-control-wrapper .gp-mobile-user-menu-list {
        display: flex;
        list-style: none;
        margin: 0;
        padding: 0;
        gap: 10px;
    }

    /* Make sure its parent shows too */
    #mobile-menu-control-wrapper .gp-mobile-user-menu {
        display: flex;
        align-items: center;
    }

    /* Optional: push hamburger to the far right */
    #mobile-menu-control-wrapper .menu-toggle {
        margin-left: auto;
    }

    /* Links styling */
    .gp-mobile-user-menu-list li {
        display: inline-block;
    }

    .gp-mobile-user-menu-list a {
        text-decoration: none;
        font-size: 14px;
    }
}

@media (max-width: 768px) {
    .menu-bar-item.gp-mobile-user-menu a {
        color: white !important;
    }
    #mobile-menu-control-wrapper .gp-mobile-user-menu-list a:hover {
        color: var(--generate-navigation-text-hover-color);
    }
    #mobile-menu-control-wrapper .gp-mobile-user-menu-list .current-menu-item > a {
        color: var(--generate-navigation-text-current-color);
    }
}

/* stop the card from expanding and allow the footer ellipsis to work, without touching other GB containers on the page */
.gb-query-loop-item > .gb-container { min-width: 0; }

/* Target only this facet (wrap it in a container, or target by facet name class) */
.facetwp-facet-liked_only .facetwp-checkbox {
	background: transparent !important;
  position: relative;
  padding-left: 56px;
  cursor: pointer;
  user-select: none;
}

/* Switch track */
.facetwp-facet-liked_only .facetwp-checkbox::before {
  content: "";
  position: absolute;
  left: 0;
  top: 50%;
  width: 44px;
  height: 24px;
  transform: translateY(-50%);
  border-radius: 999px;
  background: #ccc;
  transition: 150ms;
}

/* Switch knob */
.facetwp-facet-liked_only .facetwp-checkbox::after {
  content: "";
  position: absolute;
  left: 3px;
  top: 50%;
  width: 18px;
  height: 18px;
  transform: translateY(-50%);
  border-radius: 50%;
  background: #fff;
  transition: 150ms;
}

/* ON state */
.facetwp-facet-liked_only .facetwp-checkbox.checked::before {
  background: #333;
}

.facetwp-facet-liked_only .facetwp-checkbox.checked::after {
  left: 23px;
}

/* Hide only the FacetWP-generated "(count)" for this facet */
.facetwp-facet-liked_only .facetwp-counter {
  display: none !important;
}

// Blog images
/* GenerateBlocks image: cap to 420x420 while preserving aspect ratio */
figure.gb-block-image img.max-420 {
  width: auto !important;        /* overrides GB's width:100% */
  height: auto !important;
  max-width: 420px !important;
  max-height: 420px !important;
  display: block;
}

img.max-420 {
  max-width: 420px !important;
  max-height: 420px !important;
  width: auto !important;
  height: auto !important;
  object-fit: contain;
}

.promo-bar {
  position: sticky;
  top: 0;
  z-index: 9999;
}

.promo-bar .promo-inner {
  display: flex;
  align-items: center;
  gap: 24px;
  flex-wrap: wrap;
}

.promo-bar .promo-inner p {
	margin-bottom: 0px;
}

.promo-bar .promo-close {
  cursor: pointer;
}
